/* CSS Type 02: Standalone Search Field Styling */
.search-input-field.standalone {
  width: 100%;
  padding: 12px 20px;
  background: #ffffff;
  border-radius: 8px;
  border: 1.5px solid #585DCB;
  display: flex;
  align-items: center;
  gap: 8px;
  box-shadow: 0 4px 12px rgba(88, 93, 203, 0.04);
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.search-input-field.standalone:focus-within {
  border-color: #4a4fb0;
  box-shadow: 0 4px 16px rgba(88, 93, 203, 0.12);
}

.search-input-field.standalone .search-icon {
  width: 24px;
  height: 24px;
  flex-shrink: 0;
}

.search-input-field.standalone .search-input {
  flex: 1;
  border: none;
  outline: none;
  font-size: 16px;
  font-family: 'Pretendard', -apple-system, sans-serif;
  font-weight: 500;
  color: #212121;
  background: transparent;
}

.search-input-field.standalone .search-input::placeholder {
  color: #777777;
}
